package router

import (
	"crypto/ecdsa"
	"crypto/elliptic"
	"crypto/rand"
	"testing"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

func generateTestKey() (*ecdsa.PrivateKey, error) {
	return ecdsa.GenerateKey(elliptic.P256(), rand.Reader)
}

func TestNewProxy(t *testing.T) {
	key, _ := generateTestKey()
	jwtMgr := &JWTManager{privateKey: key}

	tests := []struct {
		name        string
		sandboxInfo *types.SandboxInfo
		requestPath string
		wantErr     bool
		errContains string
	}{
		{
			name:        "nil sandbox info",
			sandboxInfo: nil,
			wantErr:     true,
			errContains: "sandbox info is required",
		},
		{
			name: "no entry points",
			sandboxInfo: &types.SandboxInfo{
				SessionID:   "session-123",
				EntryPoints: []types.SandboxEntryPoint{},
			},
			wantErr:     true,
			errContains: "no entry point found for sandbox",
		},
		{
			name: "valid proxy",
			sandboxInfo: &types.SandboxInfo{
				SessionID: "session-123",
				EntryPoints: []types.SandboxEntryPoint{
					{
						Path:     "/",
						Protocol: "http",
						Endpoint: "localhost:8080",
					},
				},
			},
			wantErr: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			proxy, err := NewProxy(tt.sandboxInfo, tt.requestPath, jwtMgr)
			if (err != nil) != tt.wantErr {
				t.Errorf("NewProxy() error = %v, wantErr %v", err, tt.wantErr)
			}
			if err != nil && tt.errContains != "" {
				if !containsString(err.Error(), tt.errContains) {
					t.Errorf("NewProxy() error = %v, should contain %v", err, tt.errContains)
				}
			}
			if !tt.wantErr && proxy == nil {
				t.Error("NewProxy() returned nil proxy without error")
			}
		})
	}
}

func TestFindEntryPoint(t *testing.T) {
	entryPoints := []types.SandboxEntryPoint{
		{Path: "/api", Protocol: "http", Endpoint: "api-server:8080"},
		{Path: "/ws", Protocol: "ws", Endpoint: "ws-server:9090"},
		{Path: "/", Protocol: "http", Endpoint: "default-server:80"},
	}

	tests := []struct {
		name        string
		entryPoints []types.SandboxEntryPoint
		requestPath string
		wantPath    string
	}{
		{
			name:        "matches api path",
			entryPoints: entryPoints,
			requestPath: "/api/v1/resource",
			wantPath:    "/api",
		},
		{
			name:        "matches websocket path",
			entryPoints: entryPoints,
			requestPath: "/ws/connect",
			wantPath:    "/ws",
		},
		{
			name:        "defaults to first when no match",
			entryPoints: entryPoints,
			requestPath: "/other/path",
			wantPath:    "/api",
		},
		{
			name:        "returns first when empty path",
			entryPoints: entryPoints,
			requestPath: "",
			wantPath:    "/api",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := findEntryPoint(tt.entryPoints, tt.requestPath)
			if result.Path != tt.wantPath {
				t.Errorf("findEntryPoint() = %v, want %v", result.Path, tt.wantPath)
			}
		})
	}
}

func TestBuildUpstreamURL(t *testing.T) {
	tests := []struct {
		name       string
		entryPoint types.SandboxEntryPoint
		wantScheme string
		wantHost   string
		wantErr    bool
	}{
		{
			name: "http with protocol prefix",
			entryPoint: types.SandboxEntryPoint{
				Protocol: "http",
				Endpoint: "server:8080",
			},
			wantScheme: "http",
			wantHost:   "server:8080",
			wantErr:    false,
		},
		{
			name: "https with protocol prefix",
			entryPoint: types.SandboxEntryPoint{
				Protocol: "https",
				Endpoint: "server:8443",
			},
			wantScheme: "https",
			wantHost:   "server:8443",
			wantErr:    false,
		},
		{
			name: "endpoint already has scheme",
			entryPoint: types.SandboxEntryPoint{
				Protocol: "",
				Endpoint: "http://server:8080",
			},
			wantScheme: "http",
			wantHost:   "server:8080",
			wantErr:    false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			url, err := buildUpstreamURL(tt.entryPoint)
			if (err != nil) != tt.wantErr {
				t.Errorf("buildUpstreamURL() error = %v, wantErr %v", err, tt.wantErr)
				return
			}
			if !tt.wantErr {
				if url.Scheme != tt.wantScheme {
					t.Errorf("buildUpstreamURL() scheme = %v, want %v", url.Scheme, tt.wantScheme)
				}
				if url.Host != tt.wantHost {
					t.Errorf("buildUpstreamURL() host = %v, want %v", url.Host, tt.wantHost)
				}
			}
		})
	}
}

func containsString(s, substr string) bool {
	return len(s) >= len(substr) && s[0:len(substr)] == substr ||
		len(s) > len(substr) && containsString(s[1:], substr)
}

