package router

import (
	"net/http"
	"net/http/httptest"
	"sync"
	"testing"

	"github.com/gin-gonic/gin"
)

func TestConcurrencyLimitMiddleware(t *testing.T) {
	tests := []struct {
		name            string
		maxRequests     int
		concurrentCalls int
		wantOverloaded  bool
	}{
		{
			name:            "allows within limit",
			maxRequests:     10,
			concurrentCalls: 5,
			wantOverloaded:  false,
		},
		{
			name:            "blocks over limit",
			maxRequests:     2,
			concurrentCalls: 5,
			wantOverloaded:  true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			gin.SetMode(gin.TestMode)

			var mu sync.Mutex
			activeCount := 0
			overloadedCount := 0

			router := gin.New()
			router.Use(ConcurrencyLimitMiddleware(tt.maxRequests))
			router.GET("/test", func(c *gin.Context) {
				mu.Lock()
				activeCount++
				mu.Unlock()

				c.JSON(http.StatusOK, gin.H{"status": "ok"})

				mu.Lock()
				activeCount--
				mu.Unlock()
			})

			var wg sync.WaitGroup
			for i := 0; i < tt.concurrentCalls; i++ {
				wg.Add(1)
				go func() {
					defer wg.Done()
					req := httptest.NewRequest(http.MethodGet, "/test", nil)
					w := httptest.NewRecorder()
					router.ServeHTTP(w, req)

					if w.Code == http.StatusTooManyRequests {
						mu.Lock()
						overloadedCount++
						mu.Unlock()
					}
				}()
			}
			wg.Wait()

			if tt.wantOverloaded && overloadedCount == 0 {
				t.Error("expected overloaded requests, got none")
			}
			if !tt.wantOverloaded && overloadedCount > 0 {
				t.Errorf("unexpected overloaded requests: %d", overloadedCount)
			}
		})
	}
}

func TestRecoveryMiddleware(t *testing.T) {
	gin.SetMode(gin.TestMode)

	router := gin.New()
	router.Use(RecoveryMiddleware())
	router.GET("/panic", func(c *gin.Context) {
		panic("test panic")
	})
	router.GET("/ok", func(c *gin.Context) {
		c.JSON(http.StatusOK, gin.H{"status": "ok"})
	})

	t.Run("recovers from panic", func(t *testing.T) {
		req := httptest.NewRequest(http.MethodGet, "/panic", nil)
		w := httptest.NewRecorder()
		router.ServeHTTP(w, req)

		if w.Code != http.StatusInternalServerError {
			t.Errorf("expected status %d, got %d", http.StatusInternalServerError, w.Code)
		}
	})

	t.Run("passes through normal requests", func(t *testing.T) {
		req := httptest.NewRequest(http.MethodGet, "/ok", nil)
		w := httptest.NewRecorder()
		router.ServeHTTP(w, req)

		if w.Code != http.StatusOK {
			t.Errorf("expected status %d, got %d", http.StatusOK, w.Code)
		}
	})
}

