package picod

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"path/filepath"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

type Server struct {
	config      *Config
	authManager *AuthManager
	startTime   time.Time
	httpServer  *http.Server
}

func NewServer(cfg *Config) (*Server, error) {
	publicKey, err := LoadPublicKeyFromEnv()
	if err != nil {
		klog.Fatalf("Failed to load public key: %v", err)
		return nil, err
	}

	workspace := cfg.Workspace
	if workspace == "" {
		wd, err := os.Getwd()
		if err != nil {
			klog.Fatalf("Failed to get working directory: %v", err)
			return nil, fmt.Errorf("failed to get working directory: %w", err)
		}
		workspace = wd
	}

	absWorkspace, err := filepath.Abs(workspace)
	if err != nil {
		klog.Fatalf("Failed to resolve workspace path: %v", err)
		return nil, fmt.Errorf("failed to resolve workspace path: %w", err)
	}

	return &Server{
		config:      &Config{Port: cfg.Port, Workspace: absWorkspace},
		authManager: NewAuthManager(publicKey),
		startTime:   time.Now(),
	}, nil
}

func (s *Server) Run() error {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Logger(), gin.Recovery())

	RegisterRoutes(router, s.config.Workspace, s.startTime, s.authManager)

