package picod

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"path/filepath"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

type Server struct {
	config      *Config
	authManager *AuthManager
	startTime   time.Time
	httpServer  *http.Server
}

func NewServer(cfg *Config) (*Server, error) {
	publicKey, err := LoadPublicKeyFromEnv()
	if err != nil {
		return nil, fmt.Errorf("failed to load public key: %w", err)
	}

	workspace := cfg.Workspace
	if workspace == "" {
		wd, err := os.Getwd()
		if err != nil {
			return nil, fmt.Errorf("failed to get working directory: %w", err)
		}
		workspace = wd
	}

	absWorkspace, err := filepath.Abs(workspace)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve workspace path: %w", err)
	}

	return &Server{
		config:      &Config{Port: cfg.Port, Workspace: absWorkspace},
		authManager: NewAuthManager(publicKey),
		startTime:   time.Now(),
	}, nil
}

func (s *Server) Run() error {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Logger(), gin.Recovery())

	RegisterRoutes(router, s.config.Workspace, s.startTime, s.authManager)

	addr := ":" + s.config.Port
	s.httpServer = &http.Server{
		Addr:              addr,
		Handler:           router,
		ReadHeaderTimeout: 10 * time.Second,
	}

	klog.Infof("Starting %s %s on %s", ServiceName, ServiceVersion, addr)
	klog.Infof("Workspace: %s", s.config.Workspace)

	if err := s.httpServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		return fmt.Errorf("server error: %w", err)
	}

	return nil
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.httpServer != nil {
		return s.httpServer.Shutdown(ctx)
	}
	return nil
}

